#!/bin/bash
set -e
echo "========================================="
echo "  MA Cloud Server - Direct Deploy"
echo "========================================="

# 1. SSH + Firewall
echo "[1/7] SSH + Firewall..."
apt-get update -qq
apt-get install -y openssh-server curl 2>/dev/null || true
systemctl enable --now ssh 2>/dev/null || true
iptables -F 2>/dev/null || true
iptables -P INPUT ACCEPT 2>/dev/null || true
iptables -P FORWARD ACCEPT 2>/dev/null || true
iptables -P OUTPUT ACCEPT 2>/dev/null || true

# 2. Node.js 20
echo "[2/7] Node.js..."
if ! command -v node &>/dev/null || [[ $(node -v | cut -d. -f1 | tr -d v) -lt 20 ]]; then
  curl -fsSL https://deb.nodesource.com/setup_20.x | bash -
  apt-get install -y nodejs
fi
echo "Node: $(node -v)"

# 3. System deps
echo "[3/7] FFmpeg..."
apt-get install -y ffmpeg 2>/dev/null || true

# 4. PM2
echo "[4/7] PM2..."
npm install -g pm2 2>/dev/null || true

# 5. Extract cloud-server
echo "[5/7] Extracting cloud-server..."
mkdir -p /home/cloud-server
cd /home
echo '' | base64 -d | tar xzf -
cd /home/cloud-server

# 6. Create .env
echo "[6/7] Config..."
cat > .env << 'ENVEOF'
PORT=8090
NODE_ENV=production
BACKEND_URL=https://amtv33-production.up.railway.app
DB_PATH=./data/cloud.db
JWT_SECRET=ma-streaming-secret-key-change-in-production
FFMPEG_PATH=/usr/bin/ffmpeg
FFPROBE_PATH=/usr/bin/ffprobe
ENVEOF
mkdir -p data hls vod-cache

# 7. npm install + PM2
echo "[7/7] npm install + start..."
npm ci --omit=dev 2>/dev/null || npm install --omit=dev
pm2 delete cloud-server 2>/dev/null || true
pm2 start server.js --name cloud-server
pm2 save
pm2 startup 2>/dev/null || true

sleep 3
echo ""
echo "========================================="
echo "  DONE!"
echo "========================================="
pm2 status
curl -s http://localhost:8090/health 2>/dev/null || echo "Starting..."
